function el(id) {
  return document.getElementById(id);
}

function renderStats(items, targetId) {
  el(targetId).innerHTML = items.map(item => `
    <div class="metric">
      <strong>${item.value}</strong>
      <span>${item.label}</span>
    </div>
  `).join("");
}

function renderFeatureCards(items, targetId, cardClass = "feature") {
  el(targetId).innerHTML = items.map(item => `
    <div class="${cardClass}">
      <strong>${item.title || item.value}</strong>
      <span>${item.text || item.label}</span>
    </div>
  `).join("");
}

function renderHero() {
  const data = window.siteData;
  el("topbar-left").textContent = `${data.brand.full} • ${data.brand.location}`;
  el("topbar-right").textContent = "Now booking hard hat tours • Delivery anticipated Spring 2027";
  el("brand-name").textContent = data.brand.name;
  el("brand-community").textContent = `at ${data.brand.community}`;
  el("hero-chip").textContent = data.hero.eyebrow;
  el("hero-minor").textContent = data.hero.titleMinor;
  el("hero-major").textContent = data.hero.titleMajor;
  el("hero-lead").textContent = data.hero.lead;
  el("hero-primary").textContent = data.hero.primaryCta;
  el("hero-secondary").textContent = data.hero.secondaryCta;
  el("hero-bg").style.backgroundImage = `
    linear-gradient(180deg, rgba(8,14,24,.12) 0%, rgba(8,14,24,.16) 30%, rgba(8,14,24,.74) 100%),
    radial-gradient(circle at 82% 18%, rgba(142,29,69,.24), transparent 18%),
    url('${data.images.hero}')
  `;
  renderStats(data.stats, "hero-stats");
}

function renderOverview() {
  const data = window.siteData.overview;
  el("overview-title").textContent = data.title;
  el("overview-body").textContent = data.body;
  el("overview-image").src = window.siteData.images.overview;
  renderFeatureCards(data.features, "overview-features");
  renderStats(data.miniStats, "overview-stats");
}

function modelPanel(model) {
  return `
    <div class="model-grid">
      <article class="card model-card">
        <div class="image">
          <img src="${model.image}" alt="${model.name} image">
          <div class="caption">${model.imageNote}</div>
        </div>
        <div class="card-body">
          <div class="eyebrow">${model.tag}</div>
          <h3 class="serif">${model.name}</h3>
          <p>${model.description}</p>
          <div class="model-meta">
            ${model.stats.map(stat => `
              <div class="mini-stat">
                <strong>${stat.value}</strong>
                <span>${stat.label}</span>
              </div>
            `).join("")}
          </div>
          <div class="badge-row">
            ${model.badges.map(badge => `<span class="badge">${badge}</span>`).join("")}
          </div>
        </div>
      </article>

      <div class="plans-grid">
        ${model.plans.map(plan => `
          <div class="plan-card">
            <h4>${plan.title}</h4>
            ${floorplans[plan.svg]}
            <p>${plan.blurb}</p>
          </div>
        `).join("")}
      </div>
    </div>
  `;
}

function renderModels() {
  const models = window.siteData.models;
  const tabs = el("model-tabs");
  const panels = el("model-panels");

  tabs.innerHTML = models.map((model, index) => `
    <button class="tab ${index === 0 ? 'active' : ''}" data-model="${model.id}" type="button">
      ${model.name}
    </button>
  `).join("");

  panels.innerHTML = models.map((model, index) => `
    <div class="model-panel ${index === 0 ? 'active' : ''}" id="${model.id}">
      ${modelPanel(model)}
    </div>
  `).join("");

  tabs.querySelectorAll(".tab").forEach(tab => {
    tab.addEventListener("click", () => {
      tabs.querySelectorAll(".tab").forEach(t => t.classList.remove("active"));
      panels.querySelectorAll(".model-panel").forEach(p => p.classList.remove("active"));
      tab.classList.add("active");
      const panel = el(tab.dataset.model);
      if (panel) panel.classList.add("active");
    });
  });
}

