function renderContact() {
  const data = window.siteData.contact;
  el("contact-title").textContent = data.title;
  el("contact-body").textContent = data.body;
  el("contact-form-title").textContent = data.formTitle;
  el("contact-form-body").textContent = data.formBody;
  renderFeatureCards(data.features, "contact-features", "contact-mini");
}

function wireForm() {
  const form = el("lead-form");
  const success = el("success");
  form.addEventListener("submit", (e) => {
    e.preventDefault();
    form.style.display = "none";
    success.style.display = "block";
  });
}

document.addEventListener("DOMContentLoaded", () => {
  renderHero();
  renderOverview();
  renderModels();
  renderHomesite();
  renderContact();
  wireForm();
});
